commit 35f6cdc36024d8e0522ee3cccd82572680cd7d78
Author: Daniel Falbel <dfalbel@gmail.com>
Date:   Thu Apr 23 14:49:07 2026 -0300

    Split lanternInit to fix GCC variable tracking note (#1454)

    * Split lanternInit into smaller functions to fix GCC variable tracking note

    The monolithic lanternInit() function (~4200 lines of LOAD_SYMBOL calls)
    triggered a "variable tracking size limit exceeded" compiler note on GCC 13.
    Split it into lanternInitManualSymbols() and lanternInitAutogenSymbols()
    helper functions called by lanternInit().

    Fixes #1452

    * Upload install log as CI artifact to inspect compiler notes
---
 .github/workflows/main.yaml           |  7 +++++++
 inst/include/lantern/lantern.h        | 31 +++++++++++++++++++++++++------
 src/lantern/include/lantern/lantern.h | 31 +++++++++++++++++++++++++------
 3 files changed, 57 insertions(+), 12 deletions(-)

diff --git a/.github/workflows/main.yaml b/.github/workflows/main.yaml
index 770ae3fe2..85e09b36f 100644
--- a/.github/workflows/main.yaml
+++ b/.github/workflows/main.yaml
@@ -88,6 +88,13 @@ jobs:
           error-on: '"error"'
           args: 'c("--no-multiarch", "--no-manual", "--as-cran")'

+      - name: Upload install log
+        if: always()
+        uses: actions/upload-artifact@v4
+        with:
+          name: install-log-${{ matrix.config.os }}-${{ matrix.config.r_version }}
+          path: check/torch.Rcheck/00install.out
+
   benchmarks:
     needs: lantern
     if: ${{ always() && needs.lantern.result != 'failed' }}
diff --git a/inst/include/lantern/lantern.h b/inst/include/lantern/lantern.h
index 325aa415d..1781d7911 100644
--- a/inst/include/lantern/lantern.h
+++ b/inst/include/lantern/lantern.h
@@ -10621,13 +10621,11 @@ bool laternCloseLibrary(void *pLib, std::string *pError)
   LOAD_SYMBOL(_lantern_optional_##name##_delete);             \


-bool lanternInit(const std::string &libPath, std::string *pError)
-{
-  if (!lanternLoadLibrary(libPath, pError))
-    return false;
-
-  lantern_loaded = true;
+// Split lanternInit into multiple smaller functions to avoid
+// "variable tracking size limit exceeded" compiler note (GH #1452)

+static bool lanternInitManualSymbols(std::string *pError)
+{
   LANTERN_OPTIONAL_LOAD_SYMBOL(dimname_list)
   LANTERN_OPTIONAL_LOAD_SYMBOL(generator)
   LANTERN_OPTIONAL_LOAD_SYMBOL(tensor)
@@ -11137,6 +11135,12 @@ LOAD_SYMBOL(_ignite_optim_param_groups_size);
 LOAD_SYMBOL(_ignite_optim_get_param_group_params);
 LOAD_SYMBOL(_ignite_optim_step);
 LOAD_SYMBOL(_ignite_optim_zero_grad);
+
+  return true;
+}
+
+static bool lanternInitAutogenSymbols(std::string *pError)
+{
   /* Autogen Symbols -- Start */
   LOAD_SYMBOL(_lantern__cast_byte_tensor_bool)
   LOAD_SYMBOL(_lantern__cast_char_tensor_bool)
@@ -14832,6 +14836,21 @@ LOAD_SYMBOL(_ignite_optim_zero_grad);
   return true;
 }

+bool lanternInit(const std::string &libPath, std::string *pError)
+{
+  if (!lanternLoadLibrary(libPath, pError))
+    return false;
+
+  lantern_loaded = true;
+
+  if (!lanternInitManualSymbols(pError))
+    return false;
+  if (!lanternInitAutogenSymbols(pError))
+    return false;
+
+  return true;
+}
+
 #else

 extern bool lanternInit(const std::string &libPath, std::string *pError);
