Author: Daniel Falbel <dfalbel@gmail.com>
Date:   Thu Apr 16 13:23:08 2026 -0300

    Single-pass cpp_clean_names with static lookup table

    Replace 11 sequential erase/remove passes with one pass over a bool[256]
    table. Negligible measured impact on short function names but cleaner code.
---
 bench/dispatch-results.md | 14 ++++++++++++++
 src/codegen.cpp           | 31 +++++++++++++++++++++----------
 2 files changed, 35 insertions(+), 10 deletions(-)

diff --git a/bench/dispatch-results.md b/bench/dispatch-results.md
index 30991060b..bc828f998 100644
--- a/bench/dispatch-results.md
+++ b/bench/dispatch-results.md
@@ -37,3 +37,17 @@ Also removed a dead debug loop in `create_fn_name`.
 | dispatch       | 6.11µs          | 5.90µs         | -3.4%  |
 | create_fn_name | 1.39µs          | 1.19µs         | -14.4% |
 | direct         | 1.52µs          | 1.56µs         | (noise)|
+
+## Fix 3: Single-pass cpp_clean_names with lookup table
+
+Replace 11 sequential `erase(std::remove(...))` passes with a single pass
+using a static `bool[256]` lookup table. Also removed the dead
+`remove_characters` vector.
+
+| expression     | median (before) | median (after) | change |
+|----------------|-----------------|----------------|--------|
+| dispatch       | 5.90µs          | 5.86µs         | (noise)|
+| create_fn_name | 1.19µs          | 1.27µs         | (noise)|
+
+Negligible impact — the generated function names are short enough that the
+multi-pass approach was already fast. Still a cleaner implementation.
diff --git a/src/codegen.cpp b/src/codegen.cpp
index fd54d7a06..8d2393e8d 100644
--- a/src/codegen.cpp
+++ b/src/codegen.cpp
@@ -177,22 +177,33 @@ inline std::string cpp_suffix(const std::vector<std::string>& arg_names,
   return out;
 }

+static const bool* get_remove_table() {
+  static bool table[256] = {};
+  static bool initialized = false;
+  if (!initialized) {
+    const char chars[] = "'\"%%#:><, *&";
+    for (const char* p = chars; *p; ++p) {
+      table[static_cast<unsigned char>(*p)] = true;
+    }
+    initialized = true;
+  }
+  return table;
+}
+
 // [[Rcpp::export]]
 std::string cpp_clean_names(const std::string& x,
                             const std::vector<std::string>& r) {
-  std::string out = x;
-  char replace;
-  int r_size = r.size();
-  for (int i = 0; i < r_size; i++) {
-    replace = r[i][0];
-    out.erase(std::remove(out.begin(), out.end(), replace), out.end());
+  const bool* table = get_remove_table();
+  std::string out;
+  out.reserve(x.size());
+  for (char c : x) {
+    if (!table[static_cast<unsigned char>(c)]) {
+      out += c;
+    }
   }
   return out;
 }

-const std::vector<std::string> remove_characters = {
-    "'", "\"", "%", "#", ":", ">", "<", ",", " ", "*", "&"};
-
 // [[Rcpp::export]]
 std::string cpp_make_function_name(const std::string& method_name,
                                    const std::vector<std::string>& arg_names,
@@ -200,7 +211,7 @@ std::string cpp_make_function_name(const std::string& method_name,
                                    const std::string& type) {
   std::string out = "cpp_torch_" + type + "_" + method_name + "_";
   out += cpp_suffix(arg_names, arg_types);
-  out = cpp_clean_names(out, remove_characters);
+  out = cpp_clean_names(out, {});
   return out;
 }

