     lanternLastErrorClear();
-    
+
+    maybe_resume_longjump();
+
     std::string error_msg = translate_error_message(std::string(last.c_str()));
-    
+
     throw Rcpp::exception(error_msg.c_str());
-  } 
+  }
 }

