+void* r_dataptr(SEXP x)
+{
+  void* p;
+  switch(TYPEOF(x))
+  {
+    case CHARSXP:   p = (void*) CHAR(x); break;
+    case LGLSXP:    p = (void*) LOGICAL(x); break;
+    case INTSXP:    p = (void*) INTEGER(x); break;
+    case REALSXP:   p = (void*) REAL(x); break;
+    case CPLXSXP:   p = (void*) COMPLEX(x); break; 
