+  o <- optimizer_fn(n$parameters, lr = 0.1)
+  n1 = nn_linear(1, 1)
+  o$add_param_group(list(params = n1$parameters, lr = 19))
+  expect_equal(o$param_groups[[1]]$lr, 0.1)
+  expect_equal(o$param_groups[[2]]$lr, 19)
+}
